nsevents <- function(x, events, df){
  # this is the same as the `ns` function,
  # except the knot locations are chosen
  # based on the event times only, not on all person-time
  probs <- seq(0,df)/df
  q <- quantile(x[events==1], probs=probs)
  ns(x, knots=q[-c(1, df+1)], Boundary.knots = q[c(1, df+1)])
} [...] formula_timesincevax_ns <- . ~ . + vax1_az + vax1_az:nsevents(tstop, outcome_event, 4) [...] formula_spacetime <- . ~ . + ns(vax1_day, 3)*region [...] robustSEs <- lmtest::coeftest(model, vcov. = sandwich::vcovCL(model, cluster = cluster, type = "HC0")) %>% broom::tidy(conf.int=FALSE, exponentiate=exponentiate)
  robustCIs <- lmtest::coefci(model, vcov. = sandwich::vcovCL(model, cluster = cluster, type = "HC0"), level = conf.level) %>% tibble::as_tibble(rownames="term") [...] vcov <- vcovCL(plrmod, cluster = cluster, type = "HC0") [...] plrmod0 <- parglm(
  formula = formula0_pw,
  data = data_plr,
  weights = sample_weights,
  family = binomial,
  control = parglmparams,
  na.action = "na.fail",
  model = FALSE
) [...] sample_weights <- function(had_outcome, sampled){
  case_when(
    had_outcome ~ 1,
    !had_outcome & !sampled ~ 0,
    !had_outcome & sampled ~ sum(!had_outcome)/sum((sampled) & !had_outcome),
    TRUE ~ NA_real_
  )
} [...] cmlinc_variance <- function(model, vcov, newdata, id, time, weights){
  # calculate variance of adjusted survival / adjusted cumulative incidence
  ...
  partial_derivative <- rowsum(wgtcmlsum, time)
  variance <- rowSums(crossprod(t(partial_derivative), vcov) * partial_derivative) # t x 1
} [...] riskdiff_variance <- function(model, vcov, newdata0, newdata1, id, time, weights){
  # calculate variance of adjusted survival / adjusted cumulative incidence
  ...
  variance <- rowSums(crossprod(t(partial_derivative), vcov) * partial_derivative) # t x 1
} [...] action_model("postest", "timesincevax", "1", "plr", 50000)

